                }
                SocialProvider.Google -> {
                    val token = performTokenRequest(
                        SocialLoginConfig.GOOGLE_TOKEN_URL,
                        mapOf(
                            "client_id" to SocialLoginConfig.GOOGLE_OAUTH_CLIENT_ID,
                            "client_secret" to SocialLoginConfig.GOOGLE_OAUTH_CLIENT_SECRET,
                            "redirect_uri" to "https://localhost/",
