    private fun parseJsonToMap(json: String): Map<String, String> {
        val result = mutableMapOf<String, String>()
        val obj = org.json.JSONObject(json)
        val keys = obj.keys()
        while (keys.hasNext()) {
            val key = keys.next()
            result[key] = obj.optString(key)
        }
        return result
    }
}

class FacebookOAuthActivity : androidx.appcompat.app.AppCompatActivity() {
    private val callbackManager by lazy { com.facebook.CallbackManager.Factory.create() }

    override fun onCreate(savedInstanceState: android.os.Bundle?) {
        super.onCreate(savedInstanceState)

        com.facebook.FacebookSdk.sdkInitialize(applicationContext)
        com.facebook.login.LoginManager.getInstance().registerCallback(
            callbackManager,
            object : com.facebook.FacebookCallback<com.facebook.login.LoginResult> {
                override fun onSuccess(result: com.facebook.login.LoginResult) {
                    val accessToken = result.accessToken.token
                    val user = SocialUser(
                        provider = SocialProvider.Facebook,
                        id = result.accessToken.userId ?: "",
                        name = null,
                        email = null,
                        accessToken = accessToken
                    )
                    SocialLoginEventBus.post(SocialLoginResult.Success(user))
                    finish()
                }

                override fun onCancel() {
                    SocialLoginEventBus.post(SocialLoginResult.Cancelled)
                    finish()
                }

                override fun onError(error: com.facebook.FacebookException) {
                    SocialLoginEventBus.post(SocialLoginResult.Error(error))
                    finish()
                }
            }
        )

        com.facebook.login.LoginManager.getInstance().logInWithReadPermissions(
            this,
            listOf("public_profile", "email")
        )
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: android.content.Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }
}

